patch:
--- a/parity_checker.v
+++ b/parity_checker.v
@@ -7,7 +7,7 @@
   output logic parity_out
 );

-  always @(data_in) begin
+  always @(*) begin
     parity_out = ^data_in;
   end

before_code:
module parity_checker_32bit (
  input logic [31:0] data_in,
  output logic parity_out
);

  always @(data_in) begin
    parity_out = ^data_in;
  end

endmodule

after_code:
module parity_checker_32bit (
  input logic [31:0] data_in,
  output logic parity_out
);

  always @(*) begin
    parity_out = ^data_in;
  end

endmodule
